INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00074', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '指紋與其他證物採證之交互影響，請選出正確者：①使用物理顯影法（physical developer），會', '["指紋顯現後進行DNA採集，非吸水性檢體上檢出率 普遍優於吸水性檢體", "Gun Blue 法採證指紋若未立即乾燥，會影響彈殼痕跡之觀察", "列印 文件若需進行列表機溯源時，不能先進行指紋增顯  ⑤1,2IND及寧海德林法均會影響後續DNA 顯現，因此需視情況考慮DNA與指紋採證優先次序", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00075', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '使用顯微鏡進行物證鑑定的觀念，請選出正確者：①選用 NA（numerical aperture）值越大之物', '["在目鏡前裝上油鏡，可進一步提升解析度", "為能有效調整光 線方向，偏光顯微鏡有兩個偏光鏡，藉以觀察物證之偏光特性", "使用浸液法測量玻璃折射率時， 配合具熱台（hotstage）的位相差顯微鏡可提升精確度", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00076', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '親子鑑定觀念，請選出正確者：①生殖細胞進行減數分裂時Y染色體中多數DNA並不參與重組', '["Y染色體也具有大量多型性的STR與單核苷酸多型性（singlenucleotidepolymorphism;SNP） 序列", "粒線體DNA之D-loop區為密碼區（coding region），為個體間變異最大區域", "根據 哈代-溫伯格定律（Hardy–Weinbergprinciple），族群的基因型頻率及等位基因頻率在不受特定干 擾情況下，會持續變動  ⑤親子關係演算模式中，將所有不能排除的對象都納入計算的模式，稱 為RMNE法（randommannotexcluded）", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00077', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關DNA鑑定實務，請選出正確者：①dNTP可使合成中的DNA鏈終止反應，故可用來做為定', '["親子指數PI（PaternityIndex）之計算，PI=X/Y，其中Y為隨機男子具有此生父必 備對偶基因之頻率", "CODIS鑑定系統中，作為性別判定的Amelogenin，其乃是一個基因", "STR DNA並非基因，不會產製出蛋白質  ⑤STR分析出現之stutter訊號為偽訊號，非為對偶基因型別", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00078', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '與刑事鑑識有關之血清學運用，請選出正確者：①A 型血液是個體之紅血球細胞膜有 A 型抗體', '["酸性磷酸酶（ACP）又稱為PSA，水解後產物可與Fast blueB反應", "血液之結晶試驗，如Takayama試驗，其特異性（specificity）很高", "Luminol檢 測後之血跡仍可進行後續DNA檢測  ⑤MUP（4-methylumbelliferylphosphate）試劑可與酸性磷 酸酶反應，在紫外光下呈現螢光反應", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00079', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '現場常見毒物鑑定實務，請選出正確者：①使用微量擴散法鑑定一氧化碳時，血液檢體要放在外面，', '["檢體有硫化氫存在時，以 Na-nitroprusside 試紙檢測會變成黑色", "檢體若有 氰酸存在，加入苦味酸（picricacid）後出現紅色，並可在520nm測定吸光度定量", "公認的血液 酒精濃度與呼氣酒精濃度比值約為2100：1，但各國法令對於比例有些許變動  ⑤飲料中甲醇含量 檢驗可用變色酸（chromotropicacid）試驗法，檢驗過程需先將甲醇以高錳酸鉀等物質氧化成甲醛", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00080', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關纖維與毛髮鑑定實務，請選出正確者：①毛髮皮質內色素顆粒為髮色來源主要  ②人毛之髓', '["動物毛髮均 具有髓質，且皮毛中髓質表現最明顯的位置是在皮毛之中端", "纖維染料分析遇到同色異譜 （metamerism）之困境時，非破壞性分析方法中以偏光顯微鏡為首選  ⑤同一類之人造纖維，可 能因製程差異導致橫切面出現明顯變化", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00081', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關無機分析之儀器與分析應用，請選出正確者：①ICP-MS分析可以知悉同一元素質量數不同', '["原子序較高的元素，其背向散射電子強度會越強", "原子吸收光譜法中，火 焰式有較佳之再現性，無火焰式有較好之取樣效率及靈敏度", "中子為具單位質量但不帶電荷之 粒子，以中子轟擊樣品時，可不受靶材周圍靜電荷干擾，鑑識上常運用在射擊殘跡元素分析", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00082', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '將分析物由複雜基質分離之層析法概念，請選出正確者：①超臨界流體萃取時，須將溫度加熱至三', '["薄層分析中，R 值（retardationfactor）為分 f 析物移動距離與溶劑距離之比值", "使用薄層分析展開平板法時，分析樣品的起始線必須與展開劑 直接接觸才能獲得最精確移動數值", "使用氣相層析進行濫用藥物分析時，可用波峰滯留時間與面 積測量作為化合物之純度標準  ⑤液相層析法以液體為動相，管柱為靜相，將混合物之成分分離", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00083', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以掃描式電子顯微鏡/X-射線能譜分析儀進行無機物分析，可獲得待測物證重要資訊，下列敘述 何者正確？', '["二次電子的發射強度隨樣品所含元素原子序之增加而增強", "背向散射電子經影像轉換後，即可觀察樣品的表面形態", "二次電子及背向散射電子信號可用來作為高倍率的顯微觀察", "不同元素產生之X-射線能量均不同，一般用於樣品之破壞性元素定性及定量分析"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
